function Header({ current, navigate }) {
  const [scrolled, setScrolled] = useState(false);
  const [open, setOpen] = useState(false);
  const [hover, setHover] = useState(null);

  useEffect(() => {
    const onScroll = () => setScrolled(window.scrollY > 30);
    window.addEventListener("scroll", onScroll);
    return () => window.removeEventListener("scroll", onScroll);
  }, []);

  return (
    <header
      style={{
        position: "fixed",
        top: 0,
        left: 0,
        right: 0,
        zIndex: 100,
        background: "var(--navy)",
        borderBottom: scrolled ? "1px solid rgba(127,216,142,0.2)" : "1px solid transparent",
        transition: "all 0.3s ease",
        boxShadow: scrolled ? "0 4px 20px rgba(0,0,0,0.15)" : "none",
      }}
    >
      <div
        className="container"
        style={{
          display: "flex",
          alignItems: "center",
          justifyContent: "space-between",
          height: 76,
        }}
      >
        {/* Logo */}
        <button
          onClick={() => navigate("home")}
          style={{
            background: "none",
            border: "none",
            cursor: "pointer",
            padding: 0,
            display: "flex",
            alignItems: "center",
          }}
        >
          <Logo variant="navy" size={32} />
        </button>

        {/* Desktop nav */}
        <nav className="desktop-nav" style={{ display: "flex", gap: 2 }}>
          {NAV.map((item) => {
            const isActive =
              current === item.id ||
              (item.children && item.children.some((c) => c.id === current));
            return (
              <div
                key={item.id}
                style={{ position: "relative" }}
                onMouseEnter={() => item.children && setHover(item.id)}
                onMouseLeave={() => setHover(null)}
              >
                <button
                  onClick={() => navigate(item.id)}
                  style={{
                    background: "none",
                    border: "none",
                    padding: "10px 16px",
                    fontSize: 13,
                    fontWeight: 400,
                    color: isActive ? "var(--mint)" : "rgba(255,255,255,0.85)",
                    cursor: "pointer",
                    display: "flex",
                    alignItems: "center",
                    gap: 4,
                    letterSpacing: "0.02em",
                    fontFamily: "inherit",
                    transition: "color 0.2s",
                  }}
                  onMouseEnter={(e) => (e.currentTarget.style.color = "var(--mint)")}
                  onMouseLeave={(e) => (e.currentTarget.style.color = isActive ? "var(--mint)" : "rgba(255,255,255,0.85)")}
                >
                  {item.label}
                  {item.children && (
                    <ChevronDown size={12} style={{ opacity: 0.6 }} />
                  )}
                </button>

                {item.children && hover === item.id && (
                  <div
                    style={{
                      position: "absolute",
                      top: "100%",
                      left: 0,
                      minWidth: 240,
                      background: "white",
                      boxShadow: "0 20px 50px rgba(30,58,95,0.18)",
                      borderTop: "2px solid var(--mint)",
                      padding: "8px 0",
                      animation: "fadeIn 0.2s ease",
                    }}
                  >
                    {item.children.map((c) => (
                      <button
                        key={c.id}
                        onClick={() => {
                          navigate(c.id);
                          setHover(null);
                        }}
                        style={{
                          display: "block",
                          width: "100%",
                          textAlign: "left",
                          background: "none",
                          border: "none",
                          padding: "10px 22px",
                          fontSize: 13,
                          color: "var(--ink-2)",
                          cursor: "pointer",
                          fontFamily: "inherit",
                          transition: "all 0.2s",
                        }}
                        onMouseEnter={(e) => {
                          e.currentTarget.style.background = "var(--powder-2)";
                          e.currentTarget.style.color = "var(--navy)";
                        }}
                        onMouseLeave={(e) => {
                          e.currentTarget.style.background = "none";
                          e.currentTarget.style.color = "var(--ink-2)";
                        }}
                      >
                        {c.label}
                      </button>
                    ))}
                  </div>
                )}
              </div>
            );
          })}
        </nav>

        {/* CTA */}
        <button
          className="btn btn-mint desktop-cta"
          onClick={() => navigate("contact")}
          style={{ padding: "10px 20px", fontSize: 12 }}
        >
          Get a quote <ArrowRight size={14} />
        </button>

        {/* Mobile menu */}
        <button
          className="mobile-menu-btn"
          onClick={() => setOpen(!open)}
          style={{
            display: "none",
            background: "none",
            border: "none",
            cursor: "pointer",
            color: "white",
          }}
        >
          {open ? <X size={26} /> : <Menu size={26} />}
        </button>
      </div>

      {open && (
        <div
          style={{
            background: "var(--navy-2)",
            borderTop: "1px solid rgba(255,255,255,0.1)",
            padding: "20px 0",
            maxHeight: "calc(100vh - 76px)",
            overflowY: "auto",
          }}
        >
          <div className="container">
            {NAV.map((item) => (
              <div key={item.id} style={{ marginBottom: 8 }}>
                <button
                  onClick={() => {
                    navigate(item.id);
                    setOpen(false);
                  }}
                  style={{
                    display: "block",
                    width: "100%",
                    textAlign: "left",
                    background: "none",
                    border: "none",
                    padding: "12px 0",
                    fontSize: 16,
                    fontWeight: 600,
                    color: "white",
                    cursor: "pointer",
                    fontFamily: "inherit",
                  }}
                >
                  {item.label}
                </button>
                {item.children && (
                  <div style={{ paddingLeft: 16 }}>
                    {item.children.map((c) => (
                      <button
                        key={c.id}
                        onClick={() => {
                          navigate(c.id);
                          setOpen(false);
                        }}
                        style={{
                          display: "block",
                          width: "100%",
                          textAlign: "left",
                          background: "none",
                          border: "none",
                          padding: "8px 0",
                          fontSize: 14,
                          color: "rgba(255,255,255,0.7)",
                          cursor: "pointer",
                          fontFamily: "inherit",
                        }}
                      >
                        — {c.label}
                      </button>
                    ))}
                  </div>
                )}
              </div>
            ))}
          </div>
        </div>
      )}

      <style>{`
        @media (max-width: 1100px) { .desktop-nav { display: none !important; } .desktop-cta { display: none !important; } .mobile-menu-btn { display: block !important; } }
      `}</style>
    </header>
  );
}

